const crypto = require('crypto');

const body = $input.first();
const headers = body.headers || {};
const rawBody = JSON.stringify(body.json);
const appSecret = $env.META_APP_SECRET;
const signatureHeader = headers['x-hub-signature-256'] || '';

if (!signatureHeader) {
  console.warn('⚠️ Webhook sin firma X-Hub-Signature-256');
  return []; // Salir sin procesar
}

const expectedSig = 'sha256=' + crypto
  .createHmac('sha256', appSecret)
  .update(rawBody)
  .digest('hex');

// Comparación segura (tiempo constante)
const sigBuffer = Buffer.from(signatureHeader);
const expBuffer = Buffer.from(expectedSig);

if (sigBuffer.length !== expBuffer.length || !crypto.timingSafeEqual(sigBuffer, expBuffer)) {
  console.error('❌ Firma Meta INVÁLIDA. Posible spoofing.');
  return []; // Bloquear silenciosamente
}

console.log('✅ Firma Meta válida.');
return [$input.first()];

// Extraer y normalizar mensaje según el canal (WA, FB, IG)
const payload = $input.first().json;
const object = payload.object || '';

let mensajes = [];

if (object === 'whatsapp_business_account') {
  for (const entry of payload.entry || []) {
    for (const change of entry.changes || []) {
      const value = change.value || {};
      const messages = value.messages || [];
      const contacts = value.contacts || [];
      const phoneNumberId = value.metadata?.phone_number_id || '';

      for (const msg of messages) {
        const fromNum = msg.from;
        const msgId = msg.id;
        const msgType = msg.type;
        const nombre = contacts[0]?.profile?.name || '';

        let textoMensaje = '';
        let mediaId = null;
        let tipoMedia = 'text';

        if (msgType === 'text') {
          textoMensaje = msg.text?.body || '';
          tipoMedia = 'text';
        } else if (msgType === 'interactive') {
          const interactive = msg.interactive || {};
          if (interactive.type === 'button_reply') {
            textoMensaje = interactive.button_reply?.title || '';
          } else if (interactive.type === 'list_reply') {
            textoMensaje = interactive.list_reply?.title || '';
          }
          tipoMedia = 'text';
        } else if (msgType === 'audio') {
          mediaId = msg.audio?.id;
          tipoMedia = 'audio';
          textoMensaje = ''; // Se transcribirá con Whisper
        } else if (msgType === 'image') {
          mediaId = msg.image?.id;
          tipoMedia = 'image';
          textoMensaje = msg.image?.caption || '';
        } else {
          console.log(`Tipo de mensaje no manejado: ${msgType}`);
          continue;
        }

        mensajes.push({
          json: {
            canal: 'whatsapp',
            cliente_id: `wa:${fromNum}`,
            nombre_cliente: nombre,
            meta_message_id: msgId,
            tipo_media: tipoMedia,
            mensaje_texto: textoMensaje,
            media_id: mediaId,
            phone_number_id: phoneNumberId,
            wa_from: fromNum,
            raw_type: msgType
          }
        });
      }
    }
  }
} else if (object === 'page') {
  // Facebook Messenger
  for (const entry of payload.entry || []) {
    for (const messaging of entry.messaging || []) {
      const senderId = messaging.sender?.id;
      const text = messaging.message?.text || '';
      const msgId = messaging.message?.mid || '';
      if (!text && !messaging.message?.attachments) continue;
      mensajes.push({
        json: {
          canal: 'facebook',
          cliente_id: `fb:${senderId}`,
          nombre_cliente: '',
          meta_message_id: msgId,
          tipo_media: 'text',
          mensaje_texto: text,
          media_id: null,
          page_id: entry.id
        }
      });
    }
  }
} else if (object === 'instagram') {
  // Instagram DM
  for (const entry of payload.entry || []) {
    for (const messaging of entry.messaging || []) {
      const senderId = messaging.sender?.id;
      const text = messaging.message?.text || '';
      const msgId = messaging.message?.mid || '';
      if (!text) continue;
      mensajes.push({
        json: {
          canal: 'instagram',
          cliente_id: `ig:${senderId}`,
          nombre_cliente: '',
          meta_message_id: msgId,
          tipo_media: 'text',
          mensaje_texto: text,
          media_id: null
        }
      });
    }
  }
}

console.log(`Extraídos ${mensajes.length} mensajes del payload.`);
return mensajes;

// Unificar datos de todos los pasos anteriores en el payload para FastAPI
const msgData = $('Extraer Mensaje del Payload').item.json;

// Si hubo transcripción de audio, usar el texto de Whisper
let mensajeTexto = msgData.mensaje_texto || '';
let storageUrl = null;

try {
  const whisperData = $('Transcribir Audio (Whisper)').item.json;
  if (whisperData?.text) {
    mensajeTexto = whisperData.text;
    console.log(`Audio transcrito: "${mensajeTexto.substring(0, 80)}..."`);
  }
} catch(e) { /* No era audio */ }

try {
  const storageData = $('Subir a Firebase Storage').item.json;
  storageUrl = storageData?.signed_url || storageData?.storage_url || null;
} catch(e) { /* No había media */ }

const payload = {
  cliente_id: msgData.cliente_id,
  canal: msgData.canal,
  mensaje_texto: mensajeTexto,
  tipo_media: msgData.tipo_media,
  media_storage_url: storageUrl,
  meta_message_id: msgData.meta_message_id,
  nombre_cliente: msgData.nombre_cliente || ''
};

console.log(`Payload armado para ${payload.cliente_id} | tipo: ${payload.tipo_media}`);
return [{ json: payload }];
